#!/usr/bin/env python3
import os, base64

files = [
  ('app\\\\api\\\\revenue-split\\\\route.ts', ''),
  ('app\\\\api\\\\budgets\\\\route.ts', ''),
  ('app\\\\budget\\\\page.tsx', ''),
  ('app\\\\vat\\\\page.tsx', ''),
  ('app\\\\alerts\\\\page.tsx', ''),
  ('app\\\\invoices\\\\page.tsx', ''),
  ('app\\\\revenue-split\\\\page.tsx', ''),
]

for win_path, b64 in files:
    path = win_path.replace("\\\\", os.sep).replace("\\", os.sep)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"Written: {path}")
print("\nDone — git add . && git commit -m \"Fix remaining pages — food/bev POS data, budget AI forecast, ts-nocheck\" && vercel --prod")
